CREATE TABLE products (id BIGSERIAL PRIMARY KEY, name TEXT NOT NULL, price NUMERIC NOT NULL, category TEXT NOT NULL, "desc" TEXT, images JSONB DEFAULT '[]'::jsonb, code TEXT, stock BOOLEAN DEFAULT true, status TEXT DEFAULT 'ativo', created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL); CREATE TABLE categories (id BIGSERIAL PRIMARY KEY, name TEXT UNIQUE NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL); CREATE TABLE staff (id BIGSERIAL PRIMARY KEY, fullName TEXT NOT NULL, firstName TEXT NOT NULL, login TEXT UNIQUE NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL);